import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.CQMe4Urg.js";const g=JSON.parse('{"title":"第 11 章 评估与测试","description":"","frontmatter":{},"headers":[],"relativePath":"11-evaluation/index.md","filePath":"11-evaluation/index.md","lastUpdated":1776333512000}'),o={name:"11-evaluation/index.md"};function i(d,t,l,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="第-11-章-评估与测试" tabindex="-1">第 11 章 评估与测试 <a class="header-anchor" href="#第-11-章-评估与测试" aria-label="Permalink to &quot;第 11 章 评估与测试&quot;">​</a></h1><p>Agent 开发中最容易被忽视的一环就是评估。大多数人的开发流程是：写代码 -&gt; 手动试几个 case -&gt; 感觉差不多了 -&gt; 上线。这在传统软件里勉强能混过去，但在 Agent 开发中会出大问题——因为 Agent 的输出是非确定性的，同一个输入可能给出不同的输出，你&quot;感觉&quot;它好使，不代表它真的稳定好使。</p><p><strong>评估不是上线前的一次性检查，而是贯穿整个开发周期的持续流程。</strong> 你需要回答几个关键问题：Agent 的回答准确吗？稳定吗？快吗？贵吗？安全吗？</p><p>这一章从&quot;为什么评估很难&quot;开始，逐步教你：构建测试集、用 LLM 自动评分、搭建评估流水线、以及在生产环境中持续监控 Agent 的表现。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>你将学到</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>为什么评估很难、评估维度、手动测试方法</td><td>评估的基本思维框架，离线 vs 在线评估</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>自动化评估流水线、LLM-as-Judge、基准测试设计</td><td>用 LLM 评估 LLM，可复现的回归测试体系</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>可观测性系统、Tracing、生产监控、回归测试</td><td>LangSmith/Phoenix 接入，自建 Tracing，监控面板</td></tr></tbody></table><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/develop-tests" target="_blank" rel="noreferrer">Anthropic: Evaluations Guide</a> -- Anthropic 官方评估指南</li><li><a href="https://docs.smith.langchain.com/" target="_blank" rel="noreferrer">LangSmith Documentation</a> -- LangSmith 评估平台</li><li><a href="https://docs.ragas.io/" target="_blank" rel="noreferrer">RAGAS: RAG Evaluation Framework</a> -- RAG 评估框架</li><li><a href="https://hamel.dev/blog/posts/evals/" target="_blank" rel="noreferrer">Hamel Husain: Your AI Product Needs Evals</a> -- LLM 评估最佳实践</li><li><a href="https://arxiv.org/abs/2308.03688" target="_blank" rel="noreferrer">AgentBench (arXiv:2308.03688)</a> -- Agent 基准测试论文</li></ul>',8)])])}const p=e(o,[["render",i]]);export{g as __pageData,p as default};
